import{_ as a,o as s,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const l=JSON.parse('{"title":"ADR 006: Data Availability Client Interface","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ADR 006: Data Availability Client Interface | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"adr/adr-006-da-interface.md","filePath":"adr/adr-006-da-interface.md","lastUpdated":1753098206000}');const t=a({name:"adr/adr-006-da-interface.md"},[["render",function(a,l,t,o,p,i){return s(),n("div",null,[...l[0]||(l[0]=[e('<h1 id="adr-006-data-availability-client-interface" tabindex="-1">ADR 006: Data Availability Client Interface <a class="header-anchor" href="#adr-006-data-availability-client-interface" aria-label="Permalink to &quot;ADR 006: Data Availability Client Interface&quot;">​</a></h1><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>2021.04.30: Initial draft</li><li>2021.06.03: Init method added</li><li>2021.07.09: Added CheckBlockAvailability method, added KVStore to Init method, added missing result types</li><li>29.09.2022: Rename Optimint to rollmint</li><li>22.01.2023: Rename rollmint to Rollkit</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Rollkit requires data availability layer. Different implementations are expected.</p><h2 id="alternative-approaches" tabindex="-1">Alternative Approaches <a class="header-anchor" href="#alternative-approaches" aria-label="Permalink to &quot;Alternative Approaches&quot;">​</a></h2><blockquote><p>This section contains information around alternative options that are considered before making a decision. It should contain an explanation on why the alternative approach(es) were not chosen.</p></blockquote><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Defined interface should be very generic. Interface should consist of 5 methods: <code>Init</code>, <code>Start</code>, <code>Stop</code>, <code>SubmitBlock</code>, <code>CheckBlockAvailability</code>. There is also optional interface <code>BlockRetriever</code> for data availability layer clients that are also able to get block data. All the details are implementation-specific.</p><h2 id="detailed-design" tabindex="-1">Detailed Design <a class="header-anchor" href="#detailed-design" aria-label="Permalink to &quot;Detailed Design&quot;">​</a></h2><p>Definition of interface:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> DataAvailabilityLayerClient</span><span style="color:#B8A6FF;"> interface</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// Init is called once to allow DA client to read configuration and initialize resources.</span></span>\n<span class="line"><span style="color:#94EEFF;">\tInit</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">config </span><span style="color:#767676;">[]</span><span style="color:#B8A6FF;">byte</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> kvStore </span><span style="color:#CDA4EB;">store</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">KVStore</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> logger </span><span style="color:#CDA4EB;">log</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Logger</span><span style="color:#767676;">)</span><span style="color:#B8A6FF;"> error</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">\tStart</span><span style="color:#767676;">()</span><span style="color:#B8A6FF;"> error</span></span>\n<span class="line"><span style="color:#94EEFF;">\tStop</span><span style="color:#767676;">()</span><span style="color:#B8A6FF;"> error</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">\t// SubmitBlock submits the passed in block to the DA layer.</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// This should create a transaction which (potentially)</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// triggers a state transition in the DA layer.</span></span>\n<span class="line"><span style="color:#94EEFF;">\tSubmitBlock</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">block </span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">types</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Block</span><span style="color:#767676;">)</span><span style="color:#CDA4EB;"> ResultSubmitBlock</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">\t// CheckBlockAvailability queries DA layer to check block&#39;s data availability.</span></span>\n<span class="line"><span style="color:#94EEFF;">\tCheckBlockAvailability</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">block </span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">types</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Block</span><span style="color:#767676;">)</span><span style="color:#CDA4EB;"> ResultCheckBlock</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// BlockRetriever is additional interface that can be implemented by Data Availability Layer Client that is able to retrieve</span></span>\n<span class="line"><span style="color:#A0A0A0;">// block data from DA layer. This gives the ability to use it for block synchronization.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> BlockRetriever</span><span style="color:#B8A6FF;"> interface</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF;">\tRetrieveBlock</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">height </span><span style="color:#B8A6FF;">uint64</span><span style="color:#767676;">)</span><span style="color:#CDA4EB;"> ResultRetrieveBlock</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// TODO define an enum of different non-happy-path cases</span></span>\n<span class="line"><span style="color:#A0A0A0;">// that might need to be handled by Rollkit independent of</span></span>\n<span class="line"><span style="color:#A0A0A0;">// the underlying DA chain.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> StatusCode</span><span style="color:#B8A6FF;"> uint64</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// Data Availability return codes.</span></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#767676;"> (</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tStatusUnknown </span><span style="color:#CDA4EB;">StatusCode</span><span style="color:#767676;"> =</span><span style="color:#FFECB6;"> iota</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tStatusSuccess</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tStatusTimeout</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tStatusError</span></span>\n<span class="line"><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> DAResult</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// Code is to determine if the action succeeded.</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tCode </span><span style="color:#CDA4EB;">StatusCode</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// Message may contain DA layer specific information (like DA block height/hash, detailed error message, etc)</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tMessage </span><span style="color:#B8A6FF;">string</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// ResultSubmitBlock contains information returned from DA layer after block submission.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> ResultSubmitBlock</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#CDA4EB;">\tDAResult</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// Not sure if this needs to be bubbled up to other</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// parts of Rollkit.</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// Hash hash.Hash</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// ResultCheckBlock contains information about block availability, returned from DA layer client.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> ResultCheckBlock</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#CDA4EB;">\tDAResult</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// DataAvailable is the actual answer whether the block is available or not.</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// It can be true if and only if Code is equal to StatusSuccess.</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tDataAvailable </span><span style="color:#B8A6FF;">bool</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> ResultRetrieveBlock</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#CDA4EB;">\tDAResult</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// Block is the full block retrieved from Data Availability Layer.</span></span>\n<span class="line"><span style="color:#A0A0A0;">\t// If Code is not equal to StatusSuccess, it has to be nil.</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tBlock </span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">types</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Block</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><blockquote></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Implemented</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><blockquote><p>This section describes the consequences, after applying the decision. All consequences should be summarized here, not just the &quot;positive&quot; ones.</p></blockquote><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><h3 id="neutral" tabindex="-1">Neutral <a class="header-anchor" href="#neutral" aria-label="Permalink to &quot;Neutral&quot;">​</a></h3><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><blockquote><p>Are there any relevant PR comments, issues that led up to this, or articles referenced for why we made the given design choice? If so link them here!</p></blockquote>',22)])])}]]);export{l as __pageData,t as default};
